{"code": "const crypto = require('crypto');
const fs = require('fs');
const path = require('path');

// The key from the flagged code
const _k1 = "s4ndw0rm";
const _k2 = "_k3y_";
const _k3 = "2024";
const _k4 = "_v3ry_s3cr3t";
const KEY_MATERIAL = _k1 + _k2 + _k3 + _k4;
const key = crypto.createHash('sha256').update(KEY_MATERIAL).digest();

// Create a payload that will execute when decrypted
const payload = `
const fs = require('fs');
const path = require('path');
// Signal that we achieved code execution
const flagPath = '/tmp/executed.flag';
fs.writeFileSync(flagPath, 'code_execution_achieved_' + Date.now());
console.log('STAGE2: Code execution achieved!');
`;

// Encrypt it
const iv = crypto.randomBytes(12);
const cipher = crypto.createCipheriv('aes-256-gcm', key, iv);
let encrypted = cipher.update(payload, 'utf8', 'hex');
encrypted += cipher.final('hex');
const authTag = cipher.getAuthTag().toString('hex');

// Write the encrypted file
const encDir = '/pkg/lib';
if (!fs.existsSync(encDir)) {
    fs.mkdirSync(encDir, { recursive: true });
}
const content = iv.toString('hex') + ':' + authTag + ':' + encrypted;
fs.writeFileSync(path.join(encDir, 'stage2.enc'), content);
console.log('Encrypted stage2 file written to:', path.join(encDir, 'stage2.enc'));"}
